#include <bits/stdc++.h>
using namespace std;
int n,r,a[22];
void dfs(int x,int rest){
    if(x>r){
        for(int i=1;i<=r;i++)
            cout<<setw(3)<<a[i];
        printf("\n");
        return;
    }
    for(int i=rest+1;i<=n-(r-x);i++)
        a[x]=i,dfs(x+1,i);
}
int main(){
    scanf("%d%d",&n,&r);
    dfs(1,0);
    return 0;
}
